def json_error(message, status_code=400, details=None):
    payload = {"error": message}
    if details is not None:
        payload["details"] = details
    return jsonify(payload), status_code

def admin_required(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        if not current_user or current_user.role != Role.ADMIN.value:
            return json_error("Forbidden", 403)
        return f(*args, **kwargs)
    return wrapper

def normalize_email(email):
    return email.strip().lower()

def validate_email(email):
    return isinstance(email, str) and "@" in email and "." in email.split("@")[-1]

def validate_username(username):
    return isinstance(username, str) and 3 <= len(username.strip()) <= 50

def get_user_by_email(email, exclude_user_id=None):
    email = normalize_email(email)
    for user in users_db.values():
        if user.id != str(exclude_user_id) and normalize_email(user.email) == email:
            return user
    return None

def get_user_by_username(username, exclude_user_id=None):
    username = username.strip().lower()
    for user in users_db.values():
        if user.id != str(exclude_user_id) and user.username.strip().lower() == username:
            return user
    return None

@app.put("/api/users/<user_id>")
@admin_required
def update_user(user_id):
    user = users_db.get(str(user_id))
    if not user:
        return json_error("User not found", 404)

    if not request.is_json:
        return json_error("Request body must be JSON", 415)

    data = request.get_json(silent=True)
    if data is None:
        return json_error("Invalid JSON body", 400)

    allowed_fields = {
        "email",
        "username",
        "role",
        "account_status",
        "subscription_tier",
    }

    unknown_fields = [key for key in data.keys() if key not in allowed_fields]
    if unknown_fields:
        return json_error("Unknown fields provided", 400, {"fields": unknown_fields})

    if not data:
        return json_error("No fields provided for update", 400)

    updates = {}
    errors = {}

    if "email" in data:
        email = data["email"]
        if not validate_email(email):
            errors["email"] = "Must be a valid email address"
        else:
            email = normalize_email(email)
            if get_user_by_email(email, exclude_user_id=user.id):
                errors["email"] = "Email is already in use"
            else:
                updates["email"] = email

    if "username" in data:
        username = data["username"]
        if not validate_username(username):
            errors["username"] = "Must be a string between 3 and 50 characters"
        else:
            username = username.strip()
            if get_user_by_username(username, exclude_user_id=user.id):
                errors["username"] = "Username is already in use"
            else:
                updates["username"] = username

    if "role" in data:
        role = data["role"]
        valid_roles = {r.value for r in Role}
        if role not in valid_roles:
            errors["role"] = f"Must be one of: {', '.join(sorted(valid_roles))}"
        else:
            updates["role"] = role

    if "account_status" in data:
        account_status = data["account_status"]
        valid_statuses = {s.value for s in AccountStatus}
        if account_status not in valid_statuses:
            errors["account_status"] = f"Must be one of: {', '.join(sorted(valid_statuses))}"
        else:
            updates["account_status"] = account_status

    if "subscription_tier" in data:
        subscription_tier = data["subscription_tier"]
        valid_tiers = {t.value for t in SubscriptionTier}
        if subscription_tier not in valid_tiers:
            errors["subscription_tier"] = f"Must be one of: {', '.join(sorted(valid_tiers))}"
        else:
            updates["subscription_tier"] = subscription_tier

    if errors:
        return json_error("Validation failed", 422, errors)

    if user.id == current_user.id and "role" in updates and updates["role"] != Role.ADMIN.value:
        return json_error("Administrators cannot remove their own admin role", 403)

    for field, value in updates.items():
        setattr(user, field, value)

    return jsonify({
        "message": "User updated successfully",
        "user": user.to_dict()
    }), 200

